from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler

app = Flask(__name__)

# Configure logging
handler = RotatingFileHandler('app.log', maxBytes=10000, backupCount=1)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
app.logger.addHandler(handler)
app.logger.setLevel(logging.INFO)

def log_request_info():
    app.logger.info('Headers: %s', request.headers)
    app.logger.info('Body: %s', request.get_data())
    app.logger.info('User Info: %s', request.remote_addr)

@app.before_request
def before_request():
    log_request_info()

@app.after_request
def after_request(response):
    app.logger.info('Response: %s', response.get_data())
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    app.logger.error('Error: %s', str(e))
    return jsonify(error=str(e)), 500

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    # Simulate login logic
    if username == 'admin' and password == 'secret':
        app.logger.info('Successful login for user: %s', username)
        return jsonify(message='Login successful'), 200
    else:
        app.logger.warning('Failed login attempt for user: %s', username)
        return jsonify(message='Login failed'), 401

